// allowedAudioTypes maps MIME types to file extensions for audio uploads.
var allowedAudioTypes = map[string]string{
	"audio/mpeg":  "mp3",
	"audio/wav":   "wav",
	"audio/x-wav": "wav",
	"audio/ogg":   "ogg",
	"audio/webm":  "webm",
	"audio/mp4":   "m4a",
	"audio/x-m4a": "m4a",
	"audio/flac":  "flac",
}

// sniffBufSize is the number of bytes read for magic byte detection.
const sniffBufSize = 512

type uploadResponse struct {
	Key         string `json:"key"`
	ContentType string `json:"content_type"`
	Size        int64  `json:"size"`
}

func uploadHandler(store *storage.Client, maxSize int64) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if store == nil {
			http.Error(w, "object storage not configured", http.StatusServiceUnavailable)
			return
		}

		claims := auth.GetClaims(r.Context())
		if claims == nil {
			http.Error(w, "unauthorized", http.StatusUnauthorized)
			return
		}

		// Limit request body size
		r.Body = http.MaxBytesReader(w, r.Body, maxSize)

		if err := r.ParseMultipartForm(maxSize); err != nil {
			http.Error(w, "file too large or invalid form data", http.StatusBadRequest)
			return
		}
		defer func() {
			if r.MultipartForm != nil {
				_ = r.MultipartForm.RemoveAll()
			}
		}()

		file, header, err := r.FormFile("file")
		if err != nil {
			http.Error(w, "missing file field", http.StatusBadRequest)
			return
		}
		defer func() { _ = file.Close() }()

		// Read header bytes for content sniffing
		buf := make([]byte, sniffBufSize)
		n, err := io.ReadAtLeast(file, buf, 12)
		if err != nil {
			http.Error(w, "file too small or unreadable", http.StatusBadRequest)
			return
		}
		buf = buf[:n]

		// Sniff actual content type from magic bytes — this is the source of truth
		contentType := sniffAudioType(buf)
		if contentType == "" {
			http.Error(w, "file content does not match a supported audio format", http.StatusBadRequest)
			return
		}

		ext := allowedAudioTypes[contentType]

		// Reconstruct reader: sniffed bytes + remainder of file
		body := io.MultiReader(bytes.NewReader(buf), file)

		// Generate upload key
		uploadID := uuid.New()
		key := fmt.Sprintf("%s/uploads/%s.%s", claims.UserID, uploadID, ext)

		// Upload to S3
		if err := store.Upload(r.Context(), key, body, contentType); err != nil {
			slog.ErrorContext(r.Context(), "router: upload: s3 upload failed",
				"key", key,
				"error", err,
			)
			http.Error(w, "upload failed", http.StatusInternalServerError)
			return
		}

		slog.InfoContext(r.Context(), "router: upload: completed",
			"key", key,
			"size", header.Size,
			"content_type", contentType,
		)

		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(uploadResponse{
			Key:         key,
			ContentType: contentType,
			Size:        header.Size,
		})
	}
}

// sniffAudioType inspects magic bytes and returns the detected audio MIME type,
// or an empty string if the content does not match a known audio format.
func sniffAudioType(buf []byte) string {
	if len(buf) < 4 {
		return ""
	}

	// ID3v2 tag (MP3 with metadata)
	if bytes.HasPrefix(buf, []byte("ID3")) {
		return "audio/mpeg"
	}

	// MP3 frame sync: 0xFF followed by 0xE0+ (11 sync bits set)
	if buf[0] == 0xFF && buf[1]&0xE0 == 0xE0 {
		return "audio/mpeg"
	}

	// RIFF....WAVE (WAV)
	if len(buf) >= 12 &&
		bytes.HasPrefix(buf, []byte("RIFF")) &&
		bytes.Equal(buf[8:12], []byte("WAVE")) {
		return "audio/wav"
	}

	// OggS (Ogg Vorbis/Opus)
	if bytes.HasPrefix(buf, []byte("OggS")) {
		return "audio/ogg"
	}

	// fLaC (FLAC)
	if bytes.HasPrefix(buf, []byte("fLaC")) {
		return "audio/flac"
	}

	// EBML header (WebM / Matroska)
	if buf[0] == 0x1A && buf[1] == 0x45 && buf[2] == 0xDF && buf[3] == 0xA3 {
		return "audio/webm"
	}

	// ISO BMFF / MP4 container (M4A, MP4) — "ftyp" at offset 4
	if len(buf) >= 8 && bytes.Equal(buf[4:8], []byte("ftyp")) {
		return "audio/mp4"
	}

	return ""
}

func mimeFromFilename(name string) string {
	ext := strings.ToLower(filepath.Ext(name))
	switch ext {
	case ".mp3":
		return "audio/mpeg"
	case ".wav":
		return "audio/wav"
	case ".ogg":
		return "audio/ogg"
	case ".webm":
		return "audio/webm"
	case ".m4a":
		return "audio/mp4"
	case ".flac":
		return "audio/flac"
	default:
		return ""
	}
}
