func TestUploadHandler_NilStorage(t *testing.T) {
	handler := uploadHandler(nil, 50<<20)

	req := httptest.NewRequest(http.MethodPost, "/upload", nil)
	ctx := auth.WithClaims(req.Context(), &auth.Claims{UserID: uuid.New()})
	req = req.WithContext(ctx)

	rr := httptest.NewRecorder()
	handler.ServeHTTP(rr, req)

	if rr.Code != http.StatusServiceUnavailable {
		t.Errorf("expected 503, got %d", rr.Code)
	}
}

func TestUploadHandler_NoAuth(t *testing.T) {
	handler := uploadHandler(nil, 50<<20)

	req := httptest.NewRequest(http.MethodPost, "/upload", nil)
	rr := httptest.NewRecorder()
	handler.ServeHTTP(rr, req)

	// Without storage, returns 503 before checking auth
	// The auth middleware handles 401 before this handler is called,
	// but we still guard against nil claims
	if rr.Code != http.StatusServiceUnavailable {
		t.Errorf("expected 503 (nil storage checked first), got %d", rr.Code)
	}
}

func TestMimeFromFilename(t *testing.T) {
	tests := []struct {
		name     string
		filename string
		want     string
	}{
		{"mp3", "audio.mp3", "audio/mpeg"},
		{"wav", "recording.wav", "audio/wav"},
		{"ogg", "file.ogg", "audio/ogg"},
		{"webm", "capture.webm", "audio/webm"},
		{"m4a", "voice.m4a", "audio/mp4"},
		{"flac", "lossless.flac", "audio/flac"},
		{"unknown", "file.txt", ""},
		{"no extension", "noext", ""},
		{"uppercase", "FILE.MP3", "audio/mpeg"},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := mimeFromFilename(tt.filename)
			if got != tt.want {
				t.Errorf("mimeFromFilename(%q) = %q, want %q", tt.filename, got, tt.want)
			}
		})
	}
}

func TestAllowedAudioTypes(t *testing.T) {
	expected := map[string]string{
		"audio/mpeg":  "mp3",
		"audio/wav":   "wav",
		"audio/x-wav": "wav",
		"audio/ogg":   "ogg",
		"audio/webm":  "webm",
		"audio/mp4":   "m4a",
		"audio/x-m4a": "m4a",
		"audio/flac":  "flac",
	}

	for mime, ext := range expected {
		got, ok := allowedAudioTypes[mime]
		if !ok {
			t.Errorf("expected %q in allowedAudioTypes", mime)
			continue
		}
		if got != ext {
			t.Errorf("allowedAudioTypes[%q] = %q, want %q", mime, got, ext)
		}
	}

	// Verify non-audio types are not allowed
	disallowed := []string{"text/plain", "image/png", "video/mp4", "application/pdf"}
	for _, mime := range disallowed {
		if _, ok := allowedAudioTypes[mime]; ok {
			t.Errorf("unexpected type %q in allowedAudioTypes", mime)
		}
	}
}

func TestUploadResponse_JSON(t *testing.T) {
	resp := uploadResponse{
		Key:         "user123/uploads/abc.wav",
		ContentType: "audio/wav",
		Size:        12345,
	}

	data, err := json.Marshal(resp)
	if err != nil {
		t.Fatalf("marshal: %v", err)
	}

	var decoded uploadResponse
	if err := json.Unmarshal(data, &decoded); err != nil {
		t.Fatalf("unmarshal: %v", err)
	}

	if decoded.Key != resp.Key {
		t.Errorf("key: got %q, want %q", decoded.Key, resp.Key)
	}
	if decoded.ContentType != resp.ContentType {
		t.Errorf("content_type: got %q, want %q", decoded.ContentType, resp.ContentType)
	}
	if decoded.Size != resp.Size {
		t.Errorf("size: got %d, want %d", decoded.Size, resp.Size)
	}
}

// --- Content sniffing tests ---

func TestSniffAudioType_ValidFormats(t *testing.T) {
	tests := []struct {
		name string
		buf  []byte
		want string
	}{
		{
			name: "MP3 ID3v2 tag",
			buf:  append([]byte("ID3"), make([]byte, 20)...),
			want: "audio/mpeg",
		},
		{
			name: "MP3 frame sync 0xFFFB",
			buf:  append([]byte{0xFF, 0xFB, 0x90, 0x00}, make([]byte, 20)...),
			want: "audio/mpeg",
		},
		{
			name: "MP3 frame sync 0xFFF3",
			buf:  append([]byte{0xFF, 0xF3, 0x90, 0x00}, make([]byte, 20)...),
			want: "audio/mpeg",
		},
		{
			name: "MP3 frame sync 0xFFE0",
			buf:  append([]byte{0xFF, 0xE0, 0x00, 0x00}, make([]byte, 20)...),
			want: "audio/mpeg",
		},
		{
			name: "WAV RIFF/WAVE",
			buf: func() []byte {
				b := make([]byte, 44)
				copy(b[0:4], "RIFF")
				copy(b[8:12], "WAVE")
				return b
			}(),
			want: "audio/wav",
		},
		{
			name: "OGG",
			buf:  append([]byte("OggS"), make([]byte, 20)...),
			want: "audio/ogg",
		},
		{
			name: "FLAC",
			buf:  append([]byte("fLaC"), make([]byte, 20)...),
			want: "audio/flac",
		},
		{
			name: "WebM EBML header",
			buf:  append([]byte{0x1A, 0x45, 0xDF, 0xA3}, make([]byte, 20)...),
			want: "audio/webm",
		},
		{
			name: "M4A/MP4 ftyp",
			buf: func() []byte {
				b := make([]byte, 24)
				// Size (4 bytes) + "ftyp" + brand
				b[0], b[1], b[2], b[3] = 0x00, 0x00, 0x00, 0x20
				copy(b[4:8], "ftyp")
				copy(b[8:12], "M4A ")
				return b
			}(),
			want: "audio/mp4",
		},
		{
			name: "MP4 ftyp isom",
			buf: func() []byte {
				b := make([]byte, 24)
				b[0], b[1], b[2], b[3] = 0x00, 0x00, 0x00, 0x1C
				copy(b[4:8], "ftyp")
				copy(b[8:12], "isom")
				return b
			}(),
			want: "audio/mp4",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := sniffAudioType(tt.buf)
			if got != tt.want {
				t.Errorf("sniffAudioType() = %q, want %q", got, tt.want)
			}
		})
	}
}

func TestSniffAudioType_NonAudio(t *testing.T) {
	tests := []struct {
		name string
		buf  []byte
	}{
		{
			name: "PNG",
			buf:  append([]byte{0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A}, make([]byte, 20)...),
		},
		{
			name: "JPEG",
			buf:  append([]byte{0xFF, 0xD8, 0xFF, 0xE0}, make([]byte, 20)...),
		},
		{
			name: "PDF",
			buf:  append([]byte("%PDF-1.4"), make([]byte, 20)...),
		},
		{
			name: "plain text",
			buf:  []byte("Hello, this is just a text file with enough bytes to pass"),
		},
		{
			name: "ELF binary",
			buf:  append([]byte{0x7F, 0x45, 0x4C, 0x46}, make([]byte, 20)...),
		},
		{
			name: "GIF",
			buf:  append([]byte("GIF89a"), make([]byte, 20)...),
		},
		{
			name: "ZIP",
			buf:  append([]byte{0x50, 0x4B, 0x03, 0x04}, make([]byte, 20)...),
		},
		{
			name: "RIFF but not WAVE (AVI)",
			buf: func() []byte {
				b := make([]byte, 16)
				copy(b[0:4], "RIFF")
				copy(b[8:12], "AVI ")
				return b
			}(),
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := sniffAudioType(tt.buf)
			if got != "" {
				t.Errorf("sniffAudioType() = %q, want empty string for non-audio content", got)
			}
		})
	}
}

func TestSniffAudioType_TruncatedEmpty(t *testing.T) {
	tests := []struct {
		name string
