func TestNoContentTypeAllowed(t *testing.T) {
	// Responses with no Content-Type header should be allowed (let the parser decide)
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		// Don't set Content-Type — Go may auto-detect, but if we write raw bytes
		// with no sniffing it would be empty
		w.Header().Del("Content-Type")
		w.Header()["Content-Type"] = nil
		_, _ = w.Write([]byte("raw content"))
	}))
	defer srv.Close()

	c := NewClient(WithTransport(srv.Client().Transport))
	req, _ := http.NewRequestWithContext(context.Background(), http.MethodGet, srv.URL, nil)
	resp, err := c.Do(context.Background(), req)
	if err != nil {
		// Go's http server auto-detects Content-Type, so this might get "text/plain"
		// which is allowed. Either way, no Content-Type or text/* should pass.
		t.Fatalf("unexpected error: %v", err)
	}
	_ = resp.Body.Close()
}

