// MCPClientLookup abstracts the mcpclient.Service methods needed by middleware.
type MCPClientLookup interface {
	GetByAPIKey(ctx context.Context, keyHash string) (*mcpclient.Client, error)
	TouchLastUsed(ctx context.Context, id uuid.UUID)
}

// Auth validates the Bearer JWT token from the Authorization header.
// On success, claims are stored in the request context via auth.WithClaims.
// On failure, responds with 401 Unauthorized.
func Auth(validator auth.Validator) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			token, ok := bearerToken(r)
			if !ok {
				slog.WarnContext(r.Context(), "auth: missing or malformed authorization header",
					"request_id", requestIDFromContext(r.Context()),
					"method", r.Method,
					"path", r.URL.Path,
					"remote_addr", r.RemoteAddr,
				)
				w.Header().Set("WWW-Authenticate", `Bearer realm="flotsam"`)
				http.Error(w, "missing or malformed authorization header", http.StatusUnauthorized)
				return
			}

			claims, err := validator.Validate(token)
			if err != nil {
				slog.WarnContext(r.Context(), "auth: invalid or expired token",
					"request_id", requestIDFromContext(r.Context()),
					"method", r.Method,
					"path", r.URL.Path,
					"remote_addr", r.RemoteAddr,
					"error", err,
				)
				w.Header().Set("WWW-Authenticate", `Bearer realm="flotsam", error="invalid_token"`)
				http.Error(w, "invalid or expired token", http.StatusUnauthorized)
				return
			}

			ctx := auth.WithClaims(r.Context(), claims)
			next.ServeHTTP(w, r.WithContext(ctx))
		})
	}
}

// AuthWithAPIKey validates either a Bearer JWT or a Flotsam API key (flt_ prefix).
// JWT tokens are validated normally. API keys are hashed and looked up in the
// MCP client registry. On success, both auth.Claims and auth.MCPClientInfo are
// stored in context.
func AuthWithAPIKey(validator auth.Validator, clients MCPClientLookup) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			token, ok := bearerToken(r)
			if !ok {
				slog.WarnContext(r.Context(), "auth: missing or malformed authorization header",
					"request_id", requestIDFromContext(r.Context()),
					"method", r.Method,
					"path", r.URL.Path,
					"remote_addr", r.RemoteAddr,
				)
				w.Header().Set("WWW-Authenticate", `Bearer realm="flotsam"`)
				http.Error(w, "missing or malformed authorization header", http.StatusUnauthorized)
				return
			}

			// API key path: flt_ prefix
			if strings.HasPrefix(token, "flt_") {
				keyHash := mcpclient.HashAPIKey(token)
				client, err := clients.GetByAPIKey(r.Context(), keyHash)
				if err != nil {
					if errors.Is(err, mcpclient.ErrNotFound) {
						slog.WarnContext(r.Context(), "auth: invalid API key",
							"request_id", requestIDFromContext(r.Context()),
							"remote_addr", r.RemoteAddr,
						)
					} else {
						slog.ErrorContext(r.Context(), "auth: API key lookup error",
							"request_id", requestIDFromContext(r.Context()),
							"error", err,
						)
					}
					http.Error(w, "invalid or expired API key", http.StatusUnauthorized)
					return
				}

				// Synthesize claims from the client's owner
				claims := &auth.Claims{
					UserID:     client.OwnerID,
					ClientType: "mcp",
				}

				mcpInfo := &auth.MCPClientInfo{
					ClientID:       client.ID,
					OwnerID:        client.OwnerID,
					Name:           client.Name,
					Tools:          client.Permissions.Tools,
					MaxSensitivity: client.Permissions.MaxSensitivity,
				}

				ctx := auth.WithClaims(r.Context(), claims)
				ctx = auth.WithMCPClient(ctx, mcpInfo)

				// Update last used timestamp (best effort, async-friendly)
				go clients.TouchLastUsed(context.WithoutCancel(r.Context()), client.ID)

				next.ServeHTTP(w, r.WithContext(ctx))
				return
			}

			// JWT path
			claims, err := validator.Validate(token)
			if err != nil {
				slog.WarnContext(r.Context(), "auth: invalid or expired token",
					"request_id", requestIDFromContext(r.Context()),
					"method", r.Method,
					"path", r.URL.Path,
					"remote_addr", r.RemoteAddr,
					"error", err,
				)
				w.Header().Set("WWW-Authenticate", `Bearer realm="flotsam", error="invalid_token"`)
				http.Error(w, "invalid or expired token", http.StatusUnauthorized)
				return
			}

			ctx := auth.WithClaims(r.Context(), claims)
			next.ServeHTTP(w, r.WithContext(ctx))
		})
	}
}

// OptionalAuth validates a Bearer token if present but allows unauthenticated requests.
// If a token is present and valid, claims are stored in context.
// If a token is present but invalid, responds with 401.
// If no token is present, the request proceeds without claims.
func OptionalAuth(validator auth.Validator) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			token, ok := bearerToken(r)
			if !ok {
				next.ServeHTTP(w, r)
				return
			}

			claims, err := validator.Validate(token)
			if err != nil {
				slog.WarnContext(r.Context(), "auth: invalid or expired token",
					"request_id", requestIDFromContext(r.Context()),
					"method", r.Method,
					"path", r.URL.Path,
					"remote_addr", r.RemoteAddr,
					"error", err,
				)
				w.Header().Set("WWW-Authenticate", `Bearer realm="flotsam", error="invalid_token"`)
				http.Error(w, "invalid or expired token", http.StatusUnauthorized)
				return
			}

			ctx := auth.WithClaims(r.Context(), claims)
			next.ServeHTTP(w, r.WithContext(ctx))
		})
	}
}

// bearerToken extracts the token from "Authorization: Bearer <token>".
func bearerToken(r *http.Request) (string, bool) {
	header := r.Header.Get("Authorization")
	if header == "" {
		return "", false
	}
	parts := strings.SplitN(header, " ", 2)
	if len(parts) != 2 || !strings.EqualFold(parts[0], "bearer") {
		return "", false
	}
	token := strings.TrimSpace(parts[1])
	if token == "" {
		return "", false
	}
	return token, true
}
